    /// the last bucket.
    pub fn count_at(&self, index: usize) -> Option<u64> {
        self.counts.get(index).map(|c| c.to_u64())
    }

    /// Release the borrow and hand the counts slice back —
    /// the swap-model hand-off shape.
    pub fn into_counts(self) -> &'a mut [C] {
        self.counts
    }
}

