1	//! Demo: record synthetic latencies and print an iiac-perf-style
2	//! band table.
3	//!
4	//! - Builds a `g=7 n=30` histogram, records 1,000,000
5	//!   deterministic synthetic samples (seeded splitmix64), then
6	//!   walks `Histogram::buckets()` once to build quantile-fence
7	//!   bands plus overall/trimmed mean and stdev.
8	//! - Every stat is derived from the single bucket pass and its
9	//!   `cumulative` field, except the closing p50/p99/p99.9/max
10	//!   line, which uses `quantile()` as intended for spot reads.
11	
12	use histogram_no_std::{Config, Histogram};
13	
14	/// Deterministic 64-bit PRNG (splitmix64); same shape as the
15	/// oracle suite in `tests/oracle.rs`.
16	struct SplitMix64(u64);
17	
18	impl SplitMix64 {
19	    /// Next raw u64.
20	    fn next(&mut self) -> u64 {
21	        self.0 = self.0.wrapping_add(0x9E37_79B9_7F4A_7C15);
22	        let mut z = self.0;
23	        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
24	        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
25	        z ^ (z >> 31)
26	    }
27	}
28	
29	/// One quantile-fence band's accumulated stats: `first`/`last`
30	/// bound the recorded values it covers, `count` is its exact
31	/// rank span, `weighted_sum` accumulates bucket-midpoint mass
32	/// for the band mean.
33	#[derive(Debug, Clone, Copy, Default)]
34	struct BandAcc {
35	    first: u64,
36	    last: u64,
37	    count: u64,
38	    weighted_sum: f64,
39	}
40	
41	/// Label, printable fraction text, and fraction value for each
42	/// band fence, in ascending-rank order.
43	const FENCES: [(&str, &str, f64); 19] = [
44	    ("z4", "0.000_1", 0.000_1),
45	    ("z3", "0.001", 0.001),
46	    ("z2", "0.01", 0.01),
47	    ("p10", "0.10", 0.10),
48	    ("p20", "0.20", 0.20),
49	    ("p30", "0.30", 0.30),
50	    ("p40", "0.40", 0.40),
51	    ("p50", "0.50", 0.50),
52	    ("p60", "0.60", 0.60),
53	    ("p70", "0.70", 0.70),
54	    ("p80", "0.80", 0.80),
55	    ("p90", "0.90", 0.90),
56	    ("n2", "0.99", 0.99),
57	    ("n3", "0.999", 0.999),
58	    ("n4", "0.999_9", 0.999_9),
59	    ("n5", "0.999_99", 0.999_99),
60	    ("n6", "0.999_999", 0.999_999),
61	    ("n7", "0.999_999_9", 0.999_999_9),
62	    ("n8", "0.999_999_99", 0.999_999_99),
63	];
64	
65	/// Insert thousands-separator commas into a non-negative
66	/// integer's decimal text.
67	fn commas(n: u64) -> String {
68	    let digits = n.to_string();
69	    let bytes = digits.as_bytes();
70	    let mut out = String::with_capacity(digits.len() + digits.len() / 3);
71	    for (i, b) in bytes.iter().enumerate() {
72	        if i > 0 && (bytes.len() - i).is_multiple_of(3) {
73	            out.push(',');
74	        }
75	        out.push(*b as char);
76	    }
77	    out
78	}
79	
80	/// Format a non-negative mean as comma-grouped integer part plus
81	/// one decimal digit.
82	fn format_mean(x: f64) -> String {
83	    let rounded = (x * 10.0).round() / 10.0;
84	    let int_part = rounded.trunc() as u64;
85	    let frac_part = ((rounded - int_part as f64) * 10.0).round() as u64;
86	    format!("{}.{}", commas(int_part), frac_part)
87	}
88	
89	/// Quantile read that reports 0 on an empty histogram instead of
90	/// panicking (never hit here: the demo always records first).
91	#[allow(clippy::manual_unwrap_or, clippy::manual_unwrap_or_default)]
92	// OK: project convention forbids unwrap_or*; spelled out as a
93	// match instead of the suggested `.unwrap_or(0)`.
94	fn quantile_or_zero(h: &Histogram<'_, u32>, q: f64) -> u64 {
95	    match h.quantile(q) {
96	        Some(v) => v,
97	        None => 0,
98	    }
99	}
100	
101	/// Rank boundaries (1-based, inclusive) for every fence: fence
102	/// `k` closes at `floor(fraction_k * total)`, clamped to
103	/// `total`. The last fence with any rank span is then extended
104	/// to `total` so the printed table's final band absorbs any
105	/// leftover ranks that rounding left uncovered.
106	fn rank_boundaries(total: u64) -> [u64; FENCES.len()] {
107	    let mut boundary = [0u64; FENCES.len()];
108	    for (i, &(_, _, fraction)) in FENCES.iter().enumerate() {
109	        boundary[i] = ((fraction * total as f64).floor() as u64).min(total);
110	    }
111	    let mut last_nonzero = None;
112	    let mut prev = 0u64;
113	    for (i, &b) in boundary.iter().enumerate() {
114	        if b > prev {
115	            last_nonzero = Some(i);
116	        }
117	        prev = b;
118	    }
119	    if let Some(j) = last_nonzero {
120	        boundary[j] = total;
121	    }
122	    boundary
123	}
124	
125	/// Record 1,000,000 deterministic synthetic latency-tick samples
126	/// (seed 42) into `h`.
127	fn record_samples(h: &mut Histogram<'_, u32>) {
128	    let mut rng = SplitMix64(42);
129	    let max_value = h.config().max_value();
130	    for _ in 0..1_000_000u64 {
131	        let base = 50 + (rng.next() % 100);
132	        let v = match rng.next() % 1000 {
133	            0 => base * (1 + rng.next() % 10_000),
134	            1..=9 => base * (1 + rng.next() % 100),
135	            _ => base,
136	        }
137	        .clamp(1, max_value);
138	        h.record(v);
139	    }
140	}
141	
142	/// One pass over `h.buckets()`: distributes every recorded rank
143	/// into its quantile-fence band, and accumulates weighted
144	/// sum/sum-of-squares both over all ranks and over ranks up to
145	/// `cap` (the un-adjusted 0.99 fence, for the trimmed summary).
146	fn build_bands(
147	    h: &Histogram<'_, u32>,
148	    boundary: &[u64; FENCES.len()],
149	    cap: u64,
150	) -> (Vec<BandAcc>, f64, f64, f64, f64) {
151	    let mut bands = vec![BandAcc::default(); FENCES.len()];
152	    let mut prev_cumulative = 0u64;
153	    let mut bidx = 0usize;
154	    let mut sum_all = 0f64;
155	    let mut sumsq_all = 0f64;
156	    let mut sum_capped = 0f64;
157	    let mut sumsq_capped = 0f64;
158	
159	    for b in h.buckets() {
160	        if b.count == 0 {
161	            prev_cumulative = b.cumulative;
162	            continue;
163	        }
164	        let start = prev_cumulative + 1;
165	        let end = b.cumulative;
166	        let mid = (b.low as f64 + b.high as f64) / 2.0;
167	        let count_f = b.count as f64;
168	        sum_all += count_f * mid;
169	        sumsq_all += count_f * mid * mid;
170	
171	        if start <= cap {
172	            let seg_end = end.min(cap);
173	            let seg_n = (seg_end - start + 1) as f64;
174	            sum_capped += seg_n * mid;
175	            sumsq_capped += seg_n * mid * mid;
176	        }
177	
178	        // A bucket's rank span can cross several band fences (or
179	        // a band can span several buckets), so walk both in
180	        // lockstep rather than assuming a 1:1 match.
181	        let mut seg_start = start;
182	        while seg_start <= end && bidx < FENCES.len() {
183	            while bidx < FENCES.len() && boundary[bidx] < seg_start {
184	                bidx += 1;
185	            }
186	            let Some(band_end) = boundary.get(bidx).copied() else {
187	                break;
188	            };
189	            let seg_end = end.min(band_end);
190	            if seg_end < seg_start {
191	                break;
192	            }
193	            let seg_n = seg_end - seg_start + 1;
194	            if let Some(band) = bands.get_mut(bidx) {
195	                if band.count == 0 {
196	                    band.first = b.low;
197	                }
198	                band.last = b.high;
199	                band.count += seg_n;
200	                band.weighted_sum += seg_n as f64 * mid;
201	            }
202	            if seg_end == band_end {
203	                bidx += 1;
204	            }
205	            seg_start = seg_end + 1;
206	        }
207	
208	        prev_cumulative = b.cumulative;
209	    }
210	
211	    (bands, sum_all, sumsq_all, sum_capped, sumsq_capped)
212	}
213	
214	/// Print the band table plus the overall/trimmed summary rows.
215	fn print_table(h: &Histogram<'_, u32>) {
216	    let total = h.total();
217	    let boundary = rank_boundaries(total);
